// SAGA ORCHESTRATOR
procedure executeSaga(operations):
 completedOps = []

 for each operation in operations:
 try:
 result = operation.execute()
 completedOps.append(operation)
 except Exception:
 // Compensate in reverse order
 for op in reverse(completedOps):
 op.compensate()
 return FAILED

 return SUCCESS

