// PARENT TRANSACTION
procedure parentTransaction():
 beginTransaction()

 try:
 // Child Transaction 1
 result1 = childTransaction1()

 // Child Transaction 2 (depends on result1)
 result2 = childTransaction2(result1)

 // Child Transaction 3 (independent)
 result3 = childTransaction3()

 commit() // Commits all children
 except Exception as e:
 // Compensate completed children
 compensate(childTransaction3)
 compensate(childTransaction2)
 compensate(childTransaction1)
 rollback()

// CHILD TRANSACTION
procedure childTransaction1():
 beginTransaction() // Creates sub-transaction

 try:
 // Perform operations
 doWork()
 commit() // Child can commit independently
 return SUCCESS
 except Exception:
 rollback() // Child failure affects parent
 raise Exception
